 */
type NetworkPolicy = "allow-all" | "deny-all" | {
  /**
   * Domains to allow traffic to.
   * Use "*" prefix for wildcard matching (e.g., "*.npmjs.org").
   *
   * Accepts either:
   * - `string[]`: A simple list of domains to allow.
