		return Response.json(
			{ error: "Missing CHATGPT credentials in mediator state." },
			{ status: 500 },
		);
	}

	const requestUrl = new URL(request.url);
	const upstreamUrl = new URL(`https://chatgpt.com${normalizedPath}${requestUrl.search}`);
