	const env = loadRhapsodyMediatorEnv();

	if (request.headers.get("x-rhapsody-mediator-secret") !== env.MEDIATOR_SECRET) {
		return { ok: false, response: Response.json({ error: "Unauthorized." }, { status: 401 }) };
	}

	return { ok: true };
